import { cn } from "@/lib/utils";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Heart, MapPin, Navigation, HandMetal, Landmark, BadgeCheck } from "lucide-react";
import { Link } from "react-router-dom";
import michelinStarSvg from "@/assets/michelin-star.svg";

interface MichelinRestaurantCardProps {
  restaurant: any;
  isCompactMode: boolean;
  isFavorite: boolean;
  user: any;
  onToggleFavorite: (id: string, e: React.MouseEvent) => void;
  onStoryClick: (restaurant: any) => void;
  onClaimClick: (restaurant: any) => void;
  onNavigate: (restaurant: any) => void;
  onVerifiedClick?: () => void;
  getLocalizedField: (restaurant: any, field: string) => string;
  getTypeDisplayLabel: (type: string, lang: string) => string;
  formatName: (restaurant: any) => any;
  translations: Record<string, string> | null;
  language: string;
  distance?: number | null;
  realUserGps?: { lat: number; lng: number } | null;
  nearLandmarkLocation?: any;
  t: any;
  requireLogin: () => boolean;
  getBuildingStorySnippet: (r: any) => string | null;
  calculateDistance: (lat1: number, lng1: number, lat2: number, lng2: number) => number;
  userLocation?: any;
}

function getStarCount(stars: string | null | undefined): number {
  if (stars === "3") return 3;
  if (stars === "2") return 2;
  if (stars === "1") return 1;
  return 0;
}

export function MichelinRestaurantCard({
  restaurant,
  isCompactMode,
  isFavorite,
  user,
  onToggleFavorite,
  onStoryClick,
  onClaimClick,
  onNavigate,
  onVerifiedClick,
  getLocalizedField,
  getTypeDisplayLabel,
  formatName,
  translations,
  language,
  realUserGps,
  nearLandmarkLocation,
  t,
  requireLogin,
  getBuildingStorySnippet,
  calculateDistance,
  userLocation,
}: MichelinRestaurantCardProps) {
  const starCount = getStarCount(restaurant.michelin_stars);
  const hasStory = restaurant.photo_story_zh || restaurant.photo_story_en || restaurant.photo_story_pt;
  const snippet = getBuildingStorySnippet(restaurant);
  const isShell = restaurant.store_level === "shell" && restaurant.template !== "landmark";
  const isVerified = restaurant.store_level === "complete";

  // ---------- COMPACT MODE ----------
  if (isCompactMode) {
    return (
      <Card className="group overflow-hidden flex flex-col h-full border-border/60 hover:shadow-large transition-all duration-300 gap-0">
        <div className="relative overflow-hidden h-28">
          <img
            loading="lazy"
            src={restaurant.image_url || "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4?w=600&q=80"}
            alt={getLocalizedField(restaurant, "name")}
            className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-black/20 pointer-events-none" />

          {/* Stars top-left */}
          <div className="absolute top-1.5 left-1.5 z-30 flex items-center gap-0.5">
            {Array.from({ length: starCount }).map((_, i) => (
              <img key={i} src={michelinStarSvg} alt="" width={14} height={14} className="drop-shadow-md" />
            ))}
          </div>

          {/* Favorite top-right */}
          {user && (
            <button
              className={cn(
                "absolute top-1.5 right-1.5 z-20 h-7 w-7 flex items-center justify-center rounded-full backdrop-blur-sm transition-colors",
                isFavorite
                  ? "bg-destructive/80 hover:bg-destructive text-white"
                  : "bg-black/30 hover:bg-black/50 text-white"
              )}
              onClick={(e) => onToggleFavorite(restaurant.id, e)}
            >
              <Heart className={cn("w-3.5 h-3.5", isFavorite ? "fill-white" : "")} />
            </button>
          )}

          {/* Name overlay at bottom */}
          <div className="absolute bottom-0 inset-x-0 z-20 px-2 pb-1.5">
            <h3 className="text-sm font-semibold text-white leading-tight line-clamp-2 drop-shadow-md">
              {formatName(restaurant)}
            </h3>
          </div>
        </div>

        <div className="p-2 flex flex-col flex-grow">
          {restaurant.distance != null && (
            <div className="flex items-center gap-1 text-xs text-muted-foreground">
              <Navigation className="w-3 h-3 text-primary" />
              <span>{restaurant.distance.toFixed(1)} km</span>
            </div>
          )}
          <div className="flex-grow" />
          <Button asChild className="w-full h-7 text-xs mt-1.5" size="sm">
            <Link to={`/restaurant/${restaurant.id}`} onClick={() => sessionStorage.setItem("restaurants-nav-from-detail", "1")}>
              {t("restaurants.viewDetails")}
            </Link>
          </Button>
        </div>
      </Card>
    );
  }

  // ---------- FULL MODE ----------
  return (
    <Card className="group overflow-hidden flex flex-col h-full border-border/50 hover:shadow-large transition-all duration-300 bg-card">
      {/* Hero image — taller for cinematic feel */}
      <div className="relative overflow-hidden h-52">
        <img
          loading="lazy"
          src={restaurant.image_url || "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4?w=600&q=80"}
          alt={getLocalizedField(restaurant, "name")}
          className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105"
        />
        {/* Cinematic gradient */}
        <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-black/10 to-transparent pointer-events-none" />

        {/* Top bar: story + favorite */}
        <div className="absolute top-0 inset-x-0 z-20 flex items-start justify-between p-3">
          {/* Story breathing light */}
          {hasStory ? (
            <button
              className="group/story flex items-center gap-2"
              onClick={(e) => {
                e.stopPropagation();
                e.preventDefault();
                onStoryClick(restaurant);
              }}
            >
              <span className="relative flex h-2.5 w-2.5">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-white/70 opacity-75" />
                <span className="relative inline-flex rounded-full h-2.5 w-2.5 bg-white shadow-lg" />
              </span>
              <span className="text-[11px] text-white/70 opacity-0 group-hover/story:opacity-100 transition-opacity duration-300 drop-shadow-md">
                {language === "zh" ? "建筑故事" : language === "pt" ? "História" : "Story"}
              </span>
            </button>
          ) : (
            <div />
          )}

          {/* Favorite */}
          {user && (
            <button
              className={cn(
                "h-8 w-8 flex items-center justify-center rounded-full backdrop-blur-sm transition-colors",
                isFavorite
                  ? "bg-destructive/80 hover:bg-destructive text-white"
                  : "bg-black/25 hover:bg-black/45 text-white"
              )}
              onClick={(e) => onToggleFavorite(restaurant.id, e)}
            >
              <Heart className={cn("w-4 h-4", isFavorite ? "fill-white" : "")} />
            </button>
          )}
        </div>

        {/* Bottom overlay: name + stars + claim */}
        <div className="absolute bottom-0 inset-x-0 z-20 p-4">
          <div className="flex items-end justify-between gap-3">
            <div className="flex-1 min-w-0">
              {/* Restaurant name + Michelin rosettes inline */}
              <div className="flex items-center gap-2 flex-wrap">
                <h3 className="text-xl font-bold text-white leading-snug tracking-tight drop-shadow-lg line-clamp-2">
                  {formatName(restaurant)}
                </h3>
                <span className="inline-flex items-center gap-1 flex-shrink-0">
                  {Array.from({ length: starCount }).map((_, i) => (
                    <span key={i} className="inline-flex items-center justify-center w-6 h-6 rounded-full bg-[#C1282D] shadow-md">
                      <img src={michelinStarSvg} alt="" width={16} height={16} className="brightness-0 invert" />
                    </span>
                  ))}
                </span>
              </div>
            </div>

            {/* Verified icon */}
            {isVerified && (
              <button
                className="flex-shrink-0 flex items-center justify-center w-7 h-7 rounded-full bg-primary/90 backdrop-blur-sm shadow-soft hover:bg-primary transition-colors"
                onClick={(e) => {
                  e.stopPropagation();
                  e.preventDefault();
                  onVerifiedClick?.();
                }}
                title={t("restaurants.verifiedStore", "已认证")}
              >
                <BadgeCheck className="w-4 h-4 text-primary-foreground" />
              </button>
            )}

            {/* Claim badge */}
            {isShell && (
              <button
                className="flex-shrink-0 flex items-center gap-1.5 rounded-full bg-white/90 backdrop-blur-sm px-3 py-1.5 shadow-soft hover:bg-white transition-colors"
                onClick={(e) => {
                  e.stopPropagation();
                  e.preventDefault();
                  if (!requireLogin()) return;
                  onClaimClick(restaurant);
                }}
                title={t("restaurants.unclaimedStore", "未认领")}
              >
                <HandMetal className="w-3.5 h-3.5 text-foreground" />
                <span className="text-xs font-medium text-foreground">
                  {t("restaurants.unclaimedStore", "未认领")}
                </span>
              </button>
            )}
          </div>
        </div>
      </div>

      {/* Content area */}
      <div className="flex flex-col flex-grow p-4 pt-3 gap-2.5">
        {/* Distance + cuisine type row */}
        <div className="flex items-center gap-2 text-sm">
          {nearLandmarkLocation && realUserGps ? (
            <span className="flex items-center gap-1 font-medium text-primary">
              <Navigation className="w-3.5 h-3.5" />
              {calculateDistance(realUserGps.lat, realUserGps.lng, restaurant.lat, restaurant.lng).toFixed(1)} km
            </span>
          ) : restaurant.distance != null && !nearLandmarkLocation ? (
            <span className="flex items-center gap-1 font-medium text-primary">
              <Navigation className="w-3.5 h-3.5" />
              {restaurant.distance.toFixed(1)} km
            </span>
          ) : null}

          {/* Cuisine types as subtle tags */}
          <div className="flex items-center gap-1.5 text-muted-foreground text-xs flex-wrap">
            {restaurant.type.slice(0, 3).map((type: string, idx: number) => (
              <span
                key={idx}
                className="inline-flex items-center px-1.5 py-px rounded border border-border/50 text-[11px] text-muted-foreground"
              >
                {getTypeDisplayLabel(type, language)}
              </span>
            ))}
          </div>
        </div>

        {/* Address */}
        <div className="flex items-center gap-2 text-muted-foreground text-xs">
          <MapPin className="w-3 h-3 flex-shrink-0" />
          <span className="line-clamp-1">
            {translations && translations[restaurant.id]
              ? translations[restaurant.id].split("\n")[1] || restaurant.address
              : restaurant.address}
          </span>
        </div>

        {/* Building story snippet */}
        {snippet && (
          <div
            className="flex items-start gap-2 text-xs text-muted-foreground bg-secondary/50 rounded-lg px-3 py-2 cursor-pointer hover:bg-secondary/80 transition-colors border border-border/40"
            onClick={(e) => {
              e.stopPropagation();
              e.preventDefault();
              onStoryClick(restaurant);
            }}
          >
            <Landmark className="w-3.5 h-3.5 text-primary flex-shrink-0 mt-0.5" />
            <span className="line-clamp-2 italic leading-relaxed">{snippet}</span>
          </div>
        )}

        {/* Spacer */}
        <div className="flex-grow" />

        {/* Footer actions */}
        <div className="flex items-center gap-2 mt-1">
          <Button asChild className="flex-1" size="default">
            <Link to={`/restaurant/${restaurant.id}`} onClick={() => sessionStorage.setItem("restaurants-nav-from-detail", "1")}>
              {t("restaurants.viewDetails")}
            </Link>
          </Button>
          {userLocation && (
            <Button
              variant="outline"
              size="icon"
              onClick={() => onNavigate(restaurant)}
              title={t("restaurants.directions")}
            >
              <Navigation className="w-4 h-4" />
            </Button>
          )}
          {nearLandmarkLocation && restaurant.distance != null && (
            <div className="flex items-center gap-1 text-xs text-muted-foreground ml-auto">
              <Landmark className="w-3 h-3" />
              <span>{restaurant.distance.toFixed(1)} km</span>
            </div>
          )}
        </div>
      </div>
    </Card>
  );
}
