import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";
import { Restaurant, getTypeFilterValues } from "./useRestaurants";

export interface PaginatedFilters {
  search?: string;
  country?: string | null;
  city?: string | null;
  district?: string | null;
  template?: string; // "all" | "default" | "ghost" | "michelin" | "landmark" | "food"
  verified?: string; // "all" | "verified" | "unverified"
  types?: string[];
  activityId?: string | null;
  userLat?: number | null;
  userLng?: number | null;
  radiusKm?: number | null;
  sortByDistance?: boolean;
}

export interface PaginatedResult {
  data: Restaurant[];
  total: number;
}

export const useRestaurantsPaginated = (
  filters: PaginatedFilters,
  page: number,
  pageSize: number = 12,
) => {
  // Expand type filter values to include all DB variants
  const expandedTypes = filters.types && filters.types.length > 0
    ? [...new Set(filters.types.flatMap(t => getTypeFilterValues(t)))]
    : null;

  return useQuery({
    queryKey: [
      "restaurants-paginated",
      filters.search,
      filters.country,
      filters.city,
      filters.district,
      filters.template,
      filters.verified,
      filters.types?.join(","),
      filters.activityId,
      filters.userLat,
      filters.userLng,
      filters.radiusKm,
      filters.sortByDistance,
      page,
      pageSize,
    ],
    queryFn: async (): Promise<PaginatedResult> => {
      const { data, error } = await supabase.rpc("get_restaurants_paginated", {
        p_offset: page * pageSize,
        p_limit: pageSize,
        p_search: filters.search || null,
        p_country: filters.country || null,
        p_city: filters.city || null,
        p_district: filters.district || null,
        p_template: filters.template || null,
        p_verified: filters.verified || null,
        p_type_filter: expandedTypes,
        p_activity_id: filters.activityId || null,
        p_user_lat: filters.userLat ?? null,
        p_user_lng: filters.userLng ?? null,
        p_radius_km: filters.radiusKm ?? null,
        p_sort_by_distance: filters.sortByDistance ?? false,
      });

      if (error) throw error;

      const result = data as any;
      return {
        data: (result?.data || []).map((r: any) => ({
          ...r,
          distance: r.distance_km,
        })),
        total: result?.total || 0,
      };
    },
    staleTime: 1000 * 60 * 2,
    gcTime: 1000 * 60 * 10,
    placeholderData: (prev) => prev, // Keep previous data while loading next page
  });
};
